-- ملء محتوى عنقود "القضاء والدعوى والإثبات" (qada-dawa-ithbat) — أربعة
-- تصنيفات فرعية، كلها draft (استنفاد كامل للعنقود): شروط القاضي وأطراف
-- الدعوى، البينة والشهادة والقرائن والإقرار واليمين، الكتابة والإثبات
-- الإلكتروني، التحكيم والصلح وتنفيذ الأحكام.
-- كل تصنيف يحصل على درس واحد (lessons + lesson_sections +
-- lesson_citations)، بنفس أسلوب دروس tibb-ahkam-shariyya/tarikh-tashri
-- (تعريفي موجز: قسم body + قسم examples).
-- المصادر المعتمدة: الأحكام السلطانية للماوردي (شروط القاضي، والتحكيم
-- والصلح ضمن أبواب ولاية القضاء بالتراضي)، أدلة الإثبات في الفقه
-- الإسلامي لأحمد فراج حسين (وسائل الإثبات الخمسة)، الفقه الإسلامي
-- وأدلته لوهبة الزحيلي (الكتابة والإثبات الإلكتروني بالقياس على أصل
-- حجية الكتابة).
-- أحاديث استُشهد بها، تحقَّقت حرفياً عبر WebSearch قبل الإدراج (كلها
-- متفق عليها): "إذا حكم الحاكم فاجتهد ثم أصاب فله أجران..." (البخاري
-- 7352 ومسلم 1716، عن عمرو بن العاص)، "لو يعطى الناس بدعواهم..."
-- (البخاري 4552 ومسلم 1711، عن ابن عباس)، تحكيم سعد بن معاذ في بني
-- قريظة (البخاري 4121 ومسلم، عن أبي سعيد الخدري).
-- أربع آيات تحقَّقت حرفياً محلياً من artifacts/majalis/public/data/quran
-- عبر حقل numberInSurah: النساء 58 (الأمانة والعدل في الحكم)، البقرة
-- 282 (الشهادة والكتابة في آية الدَّين، استُشهد بمقطعين مختلفين منها
-- في درسين)، النساء 35 (التحكيم بين الزوجين).
-- idempotent (حارس NOT EXISTS بالعنوان+التصنيف) ثم status='published'
-- للتصنيفات الأربعة عند اكتمالها.
DO $$
DECLARE
  v_lesson uuid;
BEGIN
  -- 1) شروط القاضي وأطراف الدعوى
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='19123699-1972-46a0-b2a7-a6fc4a00f325' AND title='شروط تولية القضاء وأطراف الدعوى القضائية') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('شروط تولية القضاء وأطراف الدعوى القضائية', 'تعريف موجز بالشروط الواجب توفرها فيمن يتولى القضاء وبيان أطراف الدعوى الأساسيين', '19123699-1972-46a0-b2a7-a6fc4a00f325', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'شروط القاضي وأركان الدعوى', 'اشترط الفقهاء فيمن يتولى القضاء مجموعة من الشروط لضمان سلامة الأحكام وعدالتها، أبرزها كما فصّلها الماوردي في "الأحكام السلطانية": الإسلام، لأن القضاء ولاية على المسلمين لا تثبت لغيرهم؛ والبلوغ والعقل، لأن غير المكلَّف لا تصح تصرفاته؛ والحرية عند جمهور الفقهاء؛ والذكورة عند جمهور الفقهاء، خلافًا للحنفية الذين أجازوا تولي المرأة القضاء فيما تصح فيه شهادتها (غير الحدود والقصاص)؛ والعدالة، وهي استقامة الدين واجتناب الكبائر؛ وسلامة الحواس، خاصة السمع والبصر، لتعذّر التمييز بين الخصوم بدونهما؛ والعلم بأحكام الشريعة على درجة الاجتهاد، أو على الأقل معرفة راجحة بأحكام القضاء عند تعذّر وجود المجتهد المطلق في العصور المتأخرة، وهو ما استقر عليه العمل في أغلب البلاد الإسلامية بتقييد القضاء بمذهب فقهي معتمد. أما أطراف الدعوى القضائية فهم: المدَّعي، وهو من يخالف قوله الظاهر فيطالب بإثبات حقه؛ والمدَّعى عليه، وهو من يوافق قوله الظاهر فالأصل براءة ذمته حتى تقوم البينة عليه؛ ويشترط في كل منهما أهلية التقاضي (البلوغ والعقل، أو من ينوب عنه كالولي في حق القاصر)، ووضوح الدعوى وتحديدها بما يمكّن القاضي من الفصل فيها.', 1),
    (v_lesson, 'examples', 'الأمانة والعدل والاجتهاد شروط جامعة للقاضي', 'قال تعالى: ﴿إِنَّ اللَّهَ يَأْمُرُكُمْ أَن تُؤَدُّوا الْأَمَانَاتِ إِلَىٰ أَهْلِهَا وَإِذَا حَكَمْتُم بَيْنَ النَّاسِ أَن تَحْكُمُوا بِالْعَدْلِ ۚ إِنَّ اللَّهَ نِعِمَّا يَعِظُكُم بِهِ ۗ إِنَّ اللَّهَ كَانَ سَمِيعًا بَصِيرًا﴾ (النساء: 58)، وهي الأصل القرآني الجامع لشرطي الأمانة والعدل الواجب توفرهما فيمن يتولى القضاء بين الناس. وعن عمرو بن العاص رضي الله عنه أن رسول الله صلى الله عليه وسلم قال: «إذا حكم الحاكم فاجتهد ثم أصاب فله أجران، وإذا حكم فاجتهد ثم أخطأ فله أجر واحد» (متفق عليه، رواه البخاري 7352 ومسلم 1716)، وهذا الحديث دليل على اشتراط أهلية الاجتهاد فيمن يتصدى للقضاء، إذ رتّب الأجر على الاجتهاد المبني على أهلية علمية معتبرة لا على مجرد الحكم العشوائي.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'الأحكام السلطانية — الماوردي', 1);
  END IF;

  -- 2) البينة والشهادة والقرائن والإقرار واليمين
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='e3fe6e47-de7c-4858-a864-d6368154cd0c' AND title='وسائل الإثبات القضائي: البينة والشهادة والقرائن والإقرار واليمين') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('وسائل الإثبات القضائي: البينة والشهادة والقرائن والإقرار واليمين', 'تعريف موجز بأدلة الإثبات المعتبرة في القضاء الإسلامي وترتيبها عند التعارض', 'e3fe6e47-de7c-4858-a864-d6368154cd0c', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'أدلة الإثبات الخمسة وترتيبها في القوة', 'حصر فقهاء الشريعة أدلة الإثبات المعتبرة في القضاء بخمسة أدلة رئيسية. أولها: الشهادة، وهي إخبار عدلين (أو أكثر بحسب الدعوى) بما شاهداه أو علماه، وهي من أقوى أدلة الإثبات لأنها خبر مباشر من طرف ثالث محايد. ثانيها: الإقرار، وهو اعتراف المدَّعى عليه بالحق المدَّعى به، ويصفه الفقهاء بأنه "سيد الأدلة" لأن الإنسان لا يُتَّهم في الإقرار على نفسه بما يضرها. ثالثها: اليمين، وتكون في جانب المدَّعى عليه عند عجز المدَّعي عن إقامة البينة، عملاً بالأصل أن "الأصل براءة الذمة" فتُطلب اليمين ممن الأصل معه. رابعها: القرائن، وهي أمارات وأدلة ظرفية تقوي جانب أحد الخصمين دون أن ترقى لمرتبة اليقين المباشر، وقد توسّع الفقه المعاصر في الاعتداد بها خصوصًا في القضايا التي يصعب فيها الحصول على شهود مباشرين. خامسها: الكتابة والمحررات الموثقة. ويرتّب الفقهاء هذه الأدلة بحسب قوتها في الإثبات: فالإقرار في مرتبة اليقين، ثم الشهادة، ثم القرائن القوية، ثم اليمين وهي أضعفها لأنها لا تقوم إلا عند تعذر ما سواها.', 1),
    (v_lesson, 'examples', 'الشهادة والبينة أصلان قرآني ونبوي في توزيع عبء الإثبات', 'قال تعالى في آية الدَّين: ﴿... وَاسْتَشْهِدُوا شَهِيدَيْنِ مِن رِّجَالِكُمْ فَإِن لَّمْ يَكُونَا رَجُلَيْنِ فَرَجُلٌ وَامْرَأَتَانِ مِمَّن تَرْضَوْنَ مِنَ الشُّهَدَاءِ أَن تَضِلَّ إِحْدَاهُمَا فَتُذَكِّرَ إِحْدَاهُمَا الْأُخْرَىٰ﴾ (البقرة: 282)، وهي الأصل القرآني في اعتماد الشهادة دليلاً معتبراً في إثبات الحقوق. وعن ابن عباس رضي الله عنهما أن رسول الله صلى الله عليه وسلم قال: «لو يُعطى الناس بدعواهم لادَّعى رجال أموال قوم ودماءهم، ولكن البينة على المدَّعي واليمين على من أنكر» (متفق عليه، رواه البخاري 4552 ومسلم 1711)، وهذا الحديث أصل عظيم من أصول القضاء يرتّب توزيع عبء الإثبات بين طرفي الدعوى: فيُطالَب المدَّعي بالبينة لأن قوله يخالف الأصل، ويُطالَب المدَّعى عليه باليمين لأن قوله يوافق الأصل (براءة الذمة).', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'أدلة الإثبات في الفقه الإسلامي — أحمد فراج حسين', 1);
  END IF;

  -- 3) الكتابة والإثبات الإلكتروني
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='2e573679-dd6d-4e38-84ee-39eae146638b' AND title='الكتابة والإثبات الإلكتروني في الفقه الإسلامي') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('الكتابة والإثبات الإلكتروني في الفقه الإسلامي', 'تعريف موجز بحجية الكتابة دليلاً للإثبات وامتداد هذا الأصل للمحررات والتوقيعات الإلكترونية المعاصرة', '2e573679-dd6d-4e38-84ee-39eae146638b', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'من حجية الكتابة التقليدية إلى القياس على المحررات الإلكترونية', 'اعتبر الفقه الإسلامي الكتابة (المحررات الموثقة) دليلاً معتبراً من أدلة الإثبات منذ نزول آية الدَّين، التي أمرت بتوثيق الديون كتابةً حفظًا للحقوق وقطعًا للنزاع، ولذلك اعتُبرت الكتابة الموثقة (كالسجلات والعقود المكتوبة) حجة معتبرة في القضاء إذا توفرت فيها شروط الصحة كوضوح نسبتها إلى صاحبها وسلامتها من التزوير. وقد جرى الفقه المعاصر، عند بحث النوازل المستجدة كالمحررات والتوقيعات الإلكترونية، على تكييف هذا الأصل القديم (حجية الكتابة) على الوسائل الحديثة قياسًا، فاعتبر جمهور المعاصرين المحررات الإلكترونية الموثقة (كالبريد الإلكتروني المؤرشف، والرسائل الموقعة رقميًا بتوقيع إلكتروني معتمد، وسجلات المعاملات المصرفية والتجارية الإلكترونية) في حكم الكتابة المعتبرة شرعًا، ما دامت تحقق نفس المقصد الذي شرعت الكتابة لأجله: توثيق الحق ومنع الجحود، وأمكن التحقق من نسبتها لصاحبها وسلامتها من التلاعب عبر وسائل تقنية موثوقة (كالتوقيع الرقمي المشفَّر أو جهات التصديق الإلكتروني المعتمدة). ويبقى الفيصل عند التنازع في مدى حجية دليل إلكتروني معين هو مدى إمكان التحقق التقني من صحته ونسبته، فما أمكن التحقق منه بثقة أُعطي حكم الكتابة المعتبرة، وما لم يُتحقق منه بقي في مرتبة القرينة الظنية لا الدليل القاطع.', 1),
    (v_lesson, 'examples', 'علة توثيق الحقوق كتابةً في آية الدَّين', 'قال تعالى: ﴿يَا أَيُّهَا الَّذِينَ آمَنُوا إِذَا تَدَايَنتُم بِدَيْنٍ إِلَىٰ أَجَلٍ مُّسَمًّى فَاكْتُبُوهُ وَلْيَكْتُب بَّيْنَكُمْ كَاتِبٌ بِالْعَدْلِ ۚ ... ذَٰلِكُمْ أَقْسَطُ عِندَ اللَّهِ وَأَقْوَمُ لِلشَّهَادَةِ وَأَدْنَىٰ أَلَّا تَرْتَابُوا﴾ (البقرة: 282)، وهي أطول آية في القرآن الكريم وأصل مشروعية توثيق الحقوق كتابةً، وقد نص القرآن نفسه على علتها: تحقيق العدل ودفع الريبة والشك بين المتعاملين. وعلى هذه العلة القرآنية (دفع الريبة وحفظ الحق) بُني قياس الفقه المعاصر لإلحاق الوسائل الإلكترونية الموثوقة بحكم الكتابة المعتبرة، ما دامت العلة الجامعة بينهما متحققة.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'الفقه الإسلامي وأدلته — وهبة الزحيلي', 1);
  END IF;

  -- 4) التحكيم والصلح وتنفيذ الأحكام
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='dd040718-b1d6-4c86-b777-7cf6577d5c03' AND title='التحكيم والصلح وتنفيذ الأحكام القضائية') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('التحكيم والصلح وتنفيذ الأحكام القضائية', 'تعريف موجز بمشروعية التحكيم والصلح كوسيلتين بديلتين لفض النزاع، وبيان آلية تنفيذ الأحكام القضائية', 'dd040718-b1d6-4c86-b777-7cf6577d5c03', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'التحكيم بديل عن القضاء الرسمي، والصلح إنهاء رضائي للخصومة', 'التحكيم في الفقه الإسلامي هو اتفاق طرفي الخصومة على تولية شخص معيّن (غير القاضي الرسمي) الفصل في نزاع بينهما، ويشترط في المُحكَّم توفر أهلية معتبرة من العلم والعدالة تقارب شروط القاضي، ويكون حكمه ملزمًا للطرفين إذا لم يخالف نصًا شرعيًا قطعيًا. والصلح هو اتفاق بين المتنازعين على إنهاء الخصومة برضاهما، إما بتنازل أحدهما عن بعض حقه أو بتقاسم متفق عليه، وهو مشروع أصلاً، إلا صلحًا أحلَّ حرامًا أو حرَّم حلالاً فهو باطل. وقد فرَّق الفقهاء بين التحكيم والقضاء الرسمي في أمور، منها أن ولاية القاضي عامة تشمل كل من في نطاق ولايته، بينما ولاية المُحكَّم خاصة مقصورة على من تراضيا بتحكيمه، وأن حكم المُحكَّم عند بعض الفقهاء (كالحنفية) لا يُنفَّذ جبرًا إلا بإمضاء القاضي إن رجع أحد الطرفين عنه قبل صدور الحكم، بخلاف حكم القاضي النافذ بذاته. أما تنفيذ الأحكام القضائية فهو المرحلة الأخيرة لاستيفاء الحق بعد صدور الحكم، ويكون بإلزام المحكوم عليه طوعًا بتنفيذ ما قُضي به، فإن امتنع كان للسلطة القضائية (ممثلة في جهاز تنفيذي تابع لها) استخدام وسائل الإلزام الجبري المشروعة لاستيفاء الحق من المحكوم عليه أو من ماله، صيانةً لهيبة القضاء وضمانًا لعدم تحوّل الأحكام إلى مجرد أوراق بلا أثر عملي.', 1),
    (v_lesson, 'examples', 'تحكيم سعد بن معاذ في بني قريظة: تطبيق نبوي للتحكيم', 'قال تعالى: ﴿وَإِنْ خِفْتُمْ شِقَاقَ بَيْنِهِمَا فَابْعَثُوا حَكَمًا مِّنْ أَهْلِهِ وَحَكَمًا مِّنْ أَهْلِهَا إِن يُرِيدَا إِصْلَاحًا يُوَفِّقِ اللَّهُ بَيْنَهُمَا ۗ إِنَّ اللَّهَ كَانَ عَلِيمًا خَبِيرًا﴾ (النساء: 35)، وهي أصل مشروعية التحكيم في القرآن الكريم، إذ أمرت ببعث حكمين من أهل الزوجين عند خشية الشقاق بينهما بدل اللجوء المباشر للقضاء الرسمي. ومن أبرز تطبيقات التحكيم في السيرة النبوية: تحكيم سعد بن معاذ رضي الله عنه في بني قريظة، فعن أبي سعيد الخدري رضي الله عنه قال: نزل أهل قريظة على حكم سعد بن معاذ، فأرسل النبي صلى الله عليه وسلم إلى سعد فأتى على حمار، فلما دنا من المسجد قال للأنصار: «قوموا إلى سيدكم» فقال: هؤلاء نزلوا على حكمك، فقال: «تُقتل مقاتلتهم وتُسبى ذراريهم»، فقال النبي صلى الله عليه وسلم: «لقد حكمتَ فيهم بحكم الله» (متفق عليه، رواه البخاري 4121 ومسلم)، وفيه إقرار النبي صلى الله عليه وسلم لحكم المُحكَّم المتراضى عليه ووصفه بموافقته حكم الله.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'الأحكام السلطانية — الماوردي', 1);
  END IF;

